class Solution:
    def greatestLetter(self, s: str) -> str:
        lower = set()
        upper = set()
        for c in s:
            if c.islower():
                lower.add(c)
            elif c.isupper():
                upper.add(c)
        for c in range(ord('Z'), ord('A') - 1, -1):
            char = chr(c)
            if char.lower() in lower and char in upper:
                return char
        return ""

